import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello 🌱 I’m glad you reached out today. How are you feeling right now?"
    }
  ]);

  const [input, setInput] = useState("");

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ---------------- SONG LIST ---------------- */
    const songs = `
🎧 Telugu:
• Inkem Inkem Inkem Kaavaale – Geetha Govindam  
• Vintunnava – Ye Maaya Chesave  
• Samajavaragamana (Soft Version)  
• Yuvathaku Palikina Bhasha  

🎧 Hindi:
• Khairiyat – Chhichhore  
• Agar Tum Saath Ho – Tamasha  
• Phir Le Aaya Dil (Reprise)  
• Tu Jaane Na  

🎧 English:
• Fix You – Coldplay  
• Let It Be – The Beatles
`;

    /* ==================================================
       🔥 VERY IMPORTANT: SONG CHECK COMES FIRST
       ================================================== */
    if (
      text.includes("song") ||
      text.includes("music") ||
      text.includes("suggest")
    ) {
      return (
        "I’m really sorry you’re feeling stressed 🤍\n\n" +
        "Listening to calming music can sometimes help ease heavy emotions. Here are some gentle songs you might like:\n\n" +
        songs +
        "\nTake slow breaths while listening. I’m here with you."
      );
    }

    /* ---------------- GREETINGS ---------------- */
    if (["hi", "hello", "hey", "hai"].includes(text)) {
      return "Hello 🌼 How are you feeling right now?";
    }

    /* ---------------- STRESS ---------------- */
    if (
      text.includes("stressed") ||
      text.includes("stress") ||
      text.includes("overwhelmed")
    ) {
      return (
        "I’m really sorry you’re feeling this way 🤍\n\n" +
        "Stress can come from many places. What do you feel is causing this stress — studies, work, family, money, health, relationships, or future worries?"
      );
    }

    /* ---------------- CAUSES ---------------- */
    if (
      text.includes("study") ||
      text.includes("education") ||
      text.includes("exam") ||
      text.includes("college")
    ) {
      return "That sounds like a lot to handle. What part of your studies feels most overwhelming right now?";
    }

    if (text.includes("work") || text.includes("job")) {
      return "Work stress can be exhausting. Is it deadlines, workload, or pressure from others?";
    }

    if (text.includes("family")) {
      return "Family pressure can feel very heavy emotionally. What’s been happening with your family?";
    }

    if (text.includes("money")) {
      return "Financial stress can weigh heavily on the mind. What worries you most right now?";
    }

    if (text.includes("future") || text.includes("career")) {
      return "Thinking about the future can feel scary. What’s your biggest concern about it?";
    }

    /* ---------------- IMPACT ---------------- */
    if (
      text.includes("sleep") ||
      text.includes("tired") ||
      text.includes("focus") ||
      text.includes("headache")
    ) {
      return "When stress affects your body, it’s a sign you’ve been carrying too much 😔 Would you like a small calming exercise or some music right now?";
    }

    /* ---------------- FALLBACK ---------------- */
    return "Thank you for sharing 🤍 I’m listening. Can you tell me a little more about what you’re experiencing?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Share what you're feeling..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
